  },
  computed: {
    chartRef() {
      const identifier = this.detail && this.detail.identifier ? this.detail.identifier : 'chart_default'
      return `${identifier}_echarts`
    },
    chartInnerHeight() {
      return this.IsToolBox ? '100%' : 'calc(100% - 42px)'
    },
    chartShellStyle() {
      const backgroundColor = this.detail && this.detail.style ? this.detail.style.backColor : 'transparent'
      const opacity = this.detail && this.detail.style && this.detail.style.opacity !== undefined
        ? Number(this.detail.style.opacity)
        : 1
      return {
        overflow: 'visible',
        width: '100%',
        height: '100%',
        background: backgroundColor,
        opacity: opacity,
        '--view-chart-real-data-accent': this.chartThemePalette.accent,
        '--view-chart-real-data-accent-soft': this.chartThemePalette.accentSoft,
      }
    },
    chartThemePalette() {
      const paletteMap = {
        dark: { accent: '#4992ff', accentSoft: 'rgba(73, 146, 255, 0.32)', mode: 'dark' },
        chalk: { accent: '#87f7cf', accentSoft: 'rgba(135, 247, 207, 0.28)', mode: 'dark' },
        purplePassion: { accent: '#ffb980', accentSoft: 'rgba(255, 185, 128, 0.26)', mode: 'dark' },
        vintage: { accent: '#d87c7c', accentSoft: 'rgba(216, 124, 124, 0.24)', mode: 'light' },
        essos: { accent: '#893448', accentSoft: 'rgba(137, 52, 72, 0.18)', mode: 'light' },
        infographic: { accent: '#c1232b', accentSoft: 'rgba(193, 35, 43, 0.16)', mode: 'light' },
        macarons: { accent: '#2ec7c9', accentSoft: 'rgba(46, 199, 201, 0.18)', mode: 'light' },
        roma: { accent: '#e01f54', accentSoft: 'rgba(224, 31, 84, 0.16)', mode: 'light' },
        shine: { accent: '#c12e34', accentSoft: 'rgba(193, 46, 52, 0.16)', mode: 'light' },
        walden: { accent: '#3f9bc9', accentSoft: 'rgba(63, 155, 201, 0.18)', mode: 'light' },
        westeros: { accent: '#516b91', accentSoft: 'rgba(81, 107, 145, 0.18)', mode: 'light' },
        wonderland: { accent: '#4ea397', accentSoft: 'rgba(78, 163, 151, 0.18)', mode: 'light' },
      }
      return paletteMap[this.EchartsTheme] || paletteMap.dark
    },
    controlThemeClass() {
      return this.chartThemePalette.mode === 'light' ? 'view-chart-real-data-theme-light' : 'view-chart-real-data-theme-dark'
    },
    dropdownThemeClass() {
      return this.chartThemePalette.mode === 'light' ? 'view-chart-real-data-dropdown-light' : 'view-chart-real-data-dropdown-dark'
    },
    dropdownStyle() {
      return {
        width: '360px',
        maxWidth: '420px',
        maxHeight: '400px',
        overflow: 'auto',
        '--view-chart-real-data-accent': this.chartThemePalette.accent,
        '--view-chart-real-data-accent-soft': this.chartThemePalette.accentSoft,
      }
    }
  },
  methods: {
    getPopupContainer(triggerNode) {
      return document.body
    },
    syncEchartsThemeFromDetail(option) {
      if (!option || !option.style || !Array.isArray(option.style.diy)) {
        return
      }
      const themeOption = option.style.diy.find(item => item.key === 'EchartsXTheme')
      if (themeOption && themeOption.value) {
        this.EchartsTheme = themeOption.value
      }
    },
    getConditionDeviceName(condition) {
      if (!condition) {
        return ''
      }
      return condition.DeviceName || condition.deviceName || ''
    },
    resolveDeviceIdentity(node, extra) {
      const triggerNode = extra && extra.triggerNode ? extra.triggerNode : null
      const source = triggerNode && triggerNode.dataRef ? triggerNode.dataRef : (node || {})
      return {
        value: source.DeviceSN || source.deviceSN || source.uuid || source.key || source.value || '',
        name: source.DeviceName || source.deviceName || source.text || source.title || '',
        raw: source
      }
    },
    getCurrentDeviceValue() {
      return Array.isArray(this.SelectDevice) ? (this.SelectDevice[0] || '') : (this.SelectDevice || '')
    },
    normalizeDeviceRealDataResponse(res) {
      const rootList = res && res.data ? (res.data.realData || res.data.RealData || []) : []
      const rows = Array.isArray(rootList) ? rootList : []
      const result = []
      rows.forEach((item) => {
        if (!item) {
          return
        }
        const uuid = item.uuid || item.Uuid || item.mduid || item.ModelDataUuid || item.DataUUID || item.id || ''
        if (!uuid) {
          return
        }
        result.push({
          ...item,
          uuid,
          name: item.name || item.Name || item.dataName || item.title || uuid,
          title: item.title || item.name || item.Name || item.dataName || uuid,
          unit: item.unit || item.Unit || ''
        })
      })
      return result
    },
    syncSelectFromActive() {
      if (this.hasRuntimeSelection) {
        return
      }
      const active = this.detail && Array.isArray(this.detail.active) ? this.detail.active : []
      const selectedActive = active.filter(item => item && item.condition && item.condition.deviceSN && item.condition.dataID)
      if (!selectedActive.length) {
        return
      }
      const firstCondition = selectedActive[0].condition
      this.SelectDevice = firstCondition.deviceSN ? [firstCondition.deviceSN] : []
      this.SelectDeviceName = this.getConditionDeviceName(firstCondition)
      this.SelectAlarmData = selectedActive.map(item => item.condition.dataID)
      this.SelectDeviceDataList = selectedActive.map(item => ({
        title: item.condition.dataName,
        DataUUID: item.condition.dataID,
        unit: item.condition.dataUnit || ''
      }))
    },
    buildChartActiveItem(index, dataItem) {
      return {
        id: `ShowChartVariable${index + 1}`,
        name: 'configComponent.variable.ShowData',
        result: '',
        isExpression: false,
        condition: {
          deviceSN: this.getCurrentDeviceValue(),
          deviceName: this.SelectDeviceName,
          DeviceName: this.SelectDeviceName,
          selectVideoType: 0,
          isBandDevice: true,
          bandType: 1,
          dataID: dataItem.DataUUID,
          dataName: dataItem.title,
          dataUnit: dataItem.unit || '',
          operator: '',
          OperatorValue: '',
          OperatorMaxValue: '',
        },
      }
    },
    normalizeSelectedDeviceDataList(list) {
      const source = Array.isArray(list) ? list : []
      const seen = new Set()
      const normalized = []
      for (let i = 0; i < source.length; i++) {
        const item = source[i]
        if (!item || !item.DataUUID || seen.has(item.DataUUID)) {
          continue
        }
        seen.add(item.DataUUID)
        normalized.push(item)
      }
      return normalized
    },
    syncDetailToNode() {
      if (!this.GetNodeObj || !this.detail) {
        return
      }
      const currentData = this.GetNodeObj.getData ? this.GetNodeObj.getData() : {}
      const nextData = Object.assign({}, currentData, {
        detail: this.detail
      })
      if (this.GetNodeObj.setData) {
        this.GetNodeObj.setData(nextData)
      }
      console.log('[ViewRealDataSmoothChartByDevice] syncDetailToNode', {
        identifier: this.detail && this.detail.identifier,
        active: this.detail && this.detail.active
      })
    },
    syncActiveFromSelect() {
      if (!this.detail || !Array.isArray(this.detail.active)) {
        return
      }
      const selectedItems = this.normalizeSelectedDeviceDataList(this.SelectDeviceDataList)
      this.SelectDeviceDataList = selectedItems
      this.SelectAlarmData = selectedItems.map(item => item.DataUUID)
      this.detail.active = selectedItems.map((item, index) => this.buildChartActiveItem(index, item))
      this.syncDetailToNode()
      if (!this.isRestoringRuntimeSelection) {
        this.saveRuntimeSelection()
      }
      this.rebuildRuntimeSeries()
    },
    getRuntimeSelectionKey() {
      const routeKey = this.$route && this.$route.fullPath ? this.$route.fullPath : window.location.pathname
      const identifier = this.detail && this.detail.identifier ? this.detail.identifier : 'chart_default'
      return `ISMRuntimeSelection:${routeKey}:${identifier}`
    },
    saveRuntimeSelection() {
      if (typeof localStorage === 'undefined') {
        return
      }
      const payload = {
        SelectDevice: this.SelectDevice,
        SelectDeviceName: this.SelectDeviceName,
        SelectDeviceNodeInfo: this.SelectDeviceNodeInfo,
        SelectAlarmData: this.SelectAlarmData,
        SelectDeviceDataList: this.SelectDeviceDataList,
      }
      localStorage.setItem(this.getRuntimeSelectionKey(), JSON.stringify(payload))
    },
    restoreRuntimeSelection() {
      if (typeof localStorage === 'undefined') {
        return
      }
      const cache = localStorage.getItem(this.getRuntimeSelectionKey())
      if (!cache) {
        return
      }
      try {
        const payload = JSON.parse(cache)
        this.isRestoringRuntimeSelection = true
        this.SelectDevice = Array.isArray(payload.SelectDevice) ? payload.SelectDevice : (payload.SelectDevice ? [payload.SelectDevice] : [])
        this.SelectDeviceName = payload.SelectDeviceName || ''
        this.SelectDeviceNodeInfo = payload.SelectDeviceNodeInfo || {}
        this.SelectAlarmData = Array.isArray(payload.SelectAlarmData) ? payload.SelectAlarmData : []
        this.SelectDeviceDataList = Array.isArray(payload.SelectDeviceDataList) ? payload.SelectDeviceDataList : []
        this.hasRuntimeSelection = true
        this.syncActiveFromSelect()
        if (this.getCurrentDeviceValue()) {
          this.GetDeviceModelDataList(true)
        }
      } catch (e) {
        localStorage.removeItem(this.getRuntimeSelectionKey())
      } finally {
        this.isRestoringRuntimeSelection = false
      }
    },
    getMonitorTree() {
      let _t = this
      getMonitorTree().then(function (res) {
        if (res.data.code == 0) {
          _t.deviceTreeData = res.data.list || []
        }
      })
    },
    GetDeviceModelDataList(open) {
      if (open === false || !this.getCurrentDeviceValue()) {
        return
      }
      let _t = this
      this.dataZ = []
      this.frontDataZ = []
      const params = {
        uuid: this.getCurrentDeviceValue(),
        IsRemoveGW: !!(this.SelectDeviceNodeInfo && (this.SelectDeviceNodeInfo.IsRemoteGw || this.SelectDeviceNodeInfo.IsRemoveGW)),
        ProjectUuid: (this.SelectDeviceNodeInfo && (this.SelectDeviceNodeInfo.ProjectUUID || this.SelectDeviceNodeInfo.ProjectUuid)) || ''
      }
      getRealData(params).then(function (res) {
        if (res.data.code == 0) {
          _t.dataZ = _t.normalizeDeviceRealDataResponse(res)
          _t.frontDataZ = _t.dataZ.map(item => ({
            ...item,
            title: item.name || item.title || item.uuid
          }))
        }
      })
    },
    DeviceDataCharge(value) {
      this.hasRuntimeSelection = true
      this.SelectDeviceDataList = []
      const selectedValues = Array.isArray(value) ? value : []
      for (let i = 0; i < selectedValues.length; i++) {
        const selectedUuid = selectedValues[i]
        const dataItem = this.dataZ.find(item => item.uuid === selectedUuid) || {}
        if (!dataItem.uuid) {
          continue
        }
        this.SelectDeviceDataList.push({
          title: dataItem.name || dataItem.title || '',
          DataUUID: dataItem.uuid,
          unit: dataItem.unit || ''
        })
      }
      this.SelectDeviceDataList = this.normalizeSelectedDeviceDataList(this.SelectDeviceDataList)
      this.syncActiveFromSelect()
    },
    SelectTreeDevice(value, node, extra) {
      this.hasRuntimeSelection = true
      const deviceIdentity = this.resolveDeviceIdentity(node, extra)
      this.SelectDevice = deviceIdentity.value ? [deviceIdentity.value] : []
      this.SelectDeviceName = deviceIdentity.name
      this.SelectDeviceNodeInfo = deviceIdentity.raw || {}
      this.SelectAlarmData = []
      this.SelectDeviceDataList = []
      this.dataZ = []
      this.frontDataZ = []
      if (this.getCurrentDeviceValue()) {
        this.GetDeviceModelDataList(true)
      }
      this.syncActiveFromSelect()
    },
    waitChartContainerReady(view, callback, retryCount = 0) {
      if (!view) {
        return
      }
      if (view.clientWidth > 0 && view.clientHeight > 0) {
        callback()
        return
      }
      if (retryCount >= 10) {
        callback()
        return
      }
      const raf = typeof requestAnimationFrame === 'function' ? requestAnimationFrame : (fn) => setTimeout(fn, 16)
      raf(() => this.waitChartContainerReady(view, callback, retryCount + 1))
    },
    refreshChart(){
      if(this.echartsView==null)
      {
        return
      }
      this.date = []
      this.initComponents(this.detail)
    },
    applyChartConfig(option) {
      if (!option || !option.style || !Array.isArray(option.style.diy)) {
        return
      }
      for(let i = 0; i < option.style.diy.length; i++)
      {
        const diy = option.style.diy[i]
        if(diy.key=="ChartTitle")
        {
          this.option.title.text=diy.value
        }
        else if(diy.key=="ChartTimelyRefresh")
        {
          this.ChartTimelyRefresh = parseInt(diy.value)
        }
        else if(diy.key=="YMax")
        {
          if(diy.value==0)
          {
            this.option.yAxis.max = 'dataMax'
          }
          else {
            this.option.yAxis.max = diy.value
          }
        }
        else if(diy.key=="TimelyInitEcharts")
        {
          this.TimelyInitEcharts = parseInt(diy.value)
        }
        else if(diy.key=="YMin")
        {
          if(diy.value==0)
          {
            this.option.yAxis.min = 'dataMin'
          }
          else {
            this.option.yAxis.min = diy.value
          }
        }
        else if(diy.key=="EchartsWidth")
        {
          this.EchartsWidth = parseInt(diy.value)
        }
        else if(diy.key=="EchartsXRotate")
        {
          this.option.xAxis.axisLabel.rotate = parseInt(diy.value)
        }
        else if(diy.key=="EchartsXFormat")
        {
          this.EchartsXFormat = diy.value
        }
        else if(diy.key=="EchartsXTheme")
        {
          this.EchartsTheme = diy.value
        }
        else if(diy.key=="IsShowZoom")
        {
          this.IsShowZoom = parseInt(diy.value)
        }
        else if(diy.key=="ChartSeriesType")
        {
          this.ChartSeriesType = diy.value || 'line'
        }
      }
      const showZoom = this.IsShowZoom === 1 || this.IsShowZoom === '1' || this.IsShowZoom === true
      this.option.toolbox.feature.dataZoom = showZoom ? { xAxisIndex: [0], yAxisIndex: [0] } : undefined
      this.option.toolbox.feature.restore = showZoom ? {} : undefined
      this.option.dataZoom = showZoom ? [
        { type: 'inside', xAxisIndex: 0, yAxisIndex: 0, start: 0, end: 100, zoomLock: false },
        { type: 'slider', xAxisIndex: 0, start: 0, end: 100, height: 18, bottom: 6 },
        { type: 'slider', yAxisIndex: 0, start: 0, end: 100, orient: 'vertical', width: 18, right: 6, top: 48, bottom: 32 }
      ] : []
    },
    buildSeriesName(condition) {
      return `${this.getConditionDeviceName(condition) || condition.deviceSN}-${condition.dataName}`
    },
    rebuildRuntimeSeries() {
      if (!this.detail || !this.detail.active) {
        return
      }
      const currentZoom = this.captureCurrentDataZoom()
      this.option.xAxis.data = []
      this.option.legend.data = []
      this.option.series = []
      this.seriesMap = []
      this.realDataComeMap = {}
      for(let i =0;i<this.detail.active.length;i++)
      {
        const activeItem = this.detail.active[i]
        if(!activeItem || !activeItem.condition || activeItem.condition.dataName=="")
        {
          continue
        }
        const seriesName = this.buildSeriesName(activeItem.condition)
        this.option.legend.data.push(seriesName)
        let series= {
          name: seriesName,
          type: this.ChartSeriesType || 'line',
          smooth: (this.ChartSeriesType || 'line') === 'line',
          barMaxWidth: (this.EchartsWidth || 2) * 6,
          dataID:activeItem.condition.deviceSN+activeItem.condition.dataID,
          data: [],
          itemStyle: {
            normal: {
              lineStyle: {
                width:this.EchartsWidth
              }
            }
          },
          symbolSize: this.EchartsWidth,
        }
        this.option.series.push(series)
        this.seriesMap[activeItem.condition.deviceSN+activeItem.condition.dataID]=[]
      }
      if (this.option.series.length === 0) {
        return
      }
      if (this.echartsView) {
        const nextOption = {
          title: this.option.title,
          tooltip: this.option.tooltip,
          legend: this.option.legend,
          grid: this.option.grid,
          toolbox: this.option.toolbox,
          xAxis: this.option.xAxis,
          yAxis: this.option.yAxis,
          dataZoom: this.applyCurrentDataZoom(currentZoom),
          series: this.option.series
        }
        const raf = typeof requestAnimationFrame === 'function' ? requestAnimationFrame : (fn) => setTimeout(fn, 16)
        raf(() => {
          if (!this.echartsView) {
            return
          }
          this.echartsView.setOption(nextOption, true)
          this.echartsView.resize()
        })
      }
    },
    initComponents(option){
      if(this.IsToolBox)
      {
        return
      }
      // 确保 option 存在
      if (!option || !option.style) {
        console.warn('ViewRealDataSmoothChart initComponents: option or option.style is undefined')
        return
      }
      this.syncSelectFromActive()
      let i=0

      let refObj = this.chartRef
      let view = this.$refs[refObj]
      // 确保 DOM 元素存在
      if (!view) {
        console.warn('ViewRealDataSmoothChart initComponents: cannot find DOM element with ref:', refObj)
        return
      }
      if (view.clientWidth === 0 || view.clientHeight === 0) {
        this.waitChartContainerReady(view, () => this.initComponents(option))
        return
      }
      if(!this.editMode) {
        if (this.echartsView != null && (typeof this.echartsView.dispose == "function")) {
          this.echartsView.dispose()
          this.echartsView = null
          this.currentEchartsTheme = ""
        }
      }
      this.option.title.textStyle.color = option.style.foreColor
      this.option.title.textStyle.fontSize = option.style.fontSize
      this.option.title.textStyle.fontFamily  = option.style.fontFamily

      this.option.legend.textStyle.color = option.style.foreColor
      this.option.legend.textStyle.fontSize = option.style.fontSize
      this.option.legend.textStyle.fontFamily  = option.style.fontFamily

      this.option.xAxis.axisLabel.textStyle.color = option.style.foreColor
      this.option.xAxis.axisLabel.textStyle.fontSize = option.style.fontSize
      this.option.xAxis.axisLabel.textStyle.fontFamily  = option.style.fontFamily

      this.option.yAxis.axisLabel.textStyle.color = option.style.foreColor
      this.option.yAxis.axisLabel.textStyle.fontSize = option.style.fontSize
      this.option.yAxis.axisLabel.textStyle.fontFamily  = option.style.fontFamily

      this.applyChartConfig(option)
      if(this.echartsView && this.currentEchartsTheme !== this.EchartsTheme) {
        this.echartsView.dispose()
        this.echartsView = null
      }
      if (!this.echartsView) {
        this.echartsView = echarts.init(view, this.EchartsTheme);
        this.currentEchartsTheme = this.EchartsTheme
      }
      i=0
      this.animateType = option.animate.selected
      if(option.animate.isExpression)
      {
        this.isStart = false
      }
      else
      {
        this.isStart = true
      }
      for( i=0;i<option.animate.animateElement.length;i++)
      {
        if(option.animate.animateElement[i].id=="millcolorGrad")
        {
          for(let k =0;k<option.animate.animateElement[i].elementList.length;k++)
          {
            if(option.animate.animateElement[i].elementList[k].key=="startColor")
            {
              this.startColor=option.animate.animateElement[i].elementList[k].value
            }
            else if(option.animate.animateElement[i].elementList[k].key=="stopColor")
            {
              this.stopColor=option.animate.animateElement[i].elementList[k].value
            }
            else if(option.animate.animateElement[i].elementList[k].key=="animateSpeed")
            {
              this.animateSpeed=option.animate.animateElement[i].elementList[k].value
            }
          }
        }
        else if(option.animate.animateElement[i].id=="blink")
        {
          for(let k =0;k<option.animate.animateElement[i].elementList.length;k++) {
            if (option.animate.animateElement[i].elementList[k].key == "blinkSpeed") {
              this.blinkSpeed = option.animate.animateElement[i].elementList[k].value
            }
          }
        }
        else if(option.animate.animateElement[i].id=="animateSpin")
        {
          for(let k =0;k<option.animate.animateElement[i].elementList.length;k++) {
            if (option.animate.animateElement[i].elementList[k].key == "spinSpeed") {
              this.animateSpinSpeed = option.animate.animateElement[i].elementList[k].value
            }
            else if (option.animate.animateElement[i].elementList[k].key == "spinDirection") {
              this.spinDirection = option.animate.animateElement[i].elementList[k].value
            }
          }
        }
      }

      this.echartsView.resize()
      if(!this.editMode)
      {
        this.rebuildRuntimeSeries()
      }
      let _t = this
      // this.option.series[0].itemStyle.normal.color = this.progressColor
      setTimeout(function (){
        if (!_t.echartsView) {
          return
        }
        _t.echartsView.setOption(_t.option,true)
        _t.echartsView.resize()
      }, 100)
      if(!this.editMode){
        setTimeout(function (){
          _t.ReInitEcharts()
        }, 60000*this.TimelyInitEcharts)
      }
    },
    onResize() {
      if (this.echartsView) {
        this.echartsView.resize();
      }
    },
    ReInitEcharts(){
      clearInterval(this.ChartTimelyRefreshTimer)
      if (this.echartsView != null&&(typeof this.echartsView.dispose=="function")) {
        this.echartsView.clear();
        this.echartsView.dispose()
        this.echartsView = null
        this.currentEchartsTheme = ""
      }
      let defaultOption={
        title: {
          text: "",
          textStyle:{
            color:"",
            fontFamily:"",
            fontSize:"",
          }
        },
        tooltip: {
          trigger: 'axis'
        },
        legend: {
          data: ['Email', 'Union Ads', 'Video Ads', 'Direct', 'Search Engine'],
          textStyle:{
            color:"",
            fontFamily:"",
            fontSize:"",
          }
        },
        grid: {
          left: '1%',
          right: '1%',
          bottom: '1%',
          containLabel: true
        },
        toolbox: {
          feature: {
            saveAsImage: {}
          }
        },
        xAxis: {
          type: 'category',
          boundaryGap: false,
          axisLine: {
            show: false, //是否显示坐标刻度
            lineStyle: {
              color: '#eeeeee'
            }
          },
          axisLabel: {
            show: true,
            rotate:40,
            textStyle: {
              color: '#fff'
            }
          },
          data: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']
        },
        yAxis: {
          type: 'value',
          min:100,
          max:1000,
          axisLabel: {
            show: true,
            textStyle: {
              color: '#fff'
            }
          },
        },
        series: [
          {
            name: 'Email',
            type: 'line',
            stack: 'Total',
            smooth: true,
            data: [120, 132, 101, 134, 90, 230, 210]
          },
          {
            name: 'Union Ads',
            type: 'line',
            stack: 'Total',
            smooth: true,
            data: [220, 182, 191, 234, 290, 330, 310]
          },
          {
            name: 'Video Ads',
            type: 'line',
            stack: 'Total',
            smooth: true,
            data: [150, 232, 201, 154, 190, 330, 410]
          },
          {
            name: 'Direct',
            type: 'line',
            stack: 'Total',
            smooth: true,
            data: [320, 332, 301, 334, 390, 330, 320]
          },
          {
            name: 'Search Engine',
            type: 'line',
            stack: 'Total',
            smooth: true,
            data: [820, 932, 901, 934, 1290, 1330, 1320]
          }
        ]
      }
      this.option = defaultOption
      this.initComponents(this.detail)
    },
    updateView() {
      this.setOption(this.option);
    },
    // 获取当前时间
    getTime () {
      let ts = arguments[0] || 0;
      let t, h, i, s,ms,m,d,y;
      t = new Date();
      y = t.getFullYear()
      m = t.getMonth()+1
      d = t.getDate()
      h = t.getHours();
      i = t.getMinutes();
      s = t.getSeconds();
      ms = t.getMilliseconds();
      // 定义时间格式
      return y+"-"+(m < 10 ? '0' + m : m)+"-"+(d < 10 ? '0' + d : d)+" "+(h < 10 ? '0' + h : h) + ':' + (i < 10 ? '0' + i : i) + ':' + (s < 10 ? '0' + s : s)+"."+ms;
    },
    getSecondByDateSub(begin)
    {
      let beginSplit = begin.split(" ")
      let beginstr = ""
      let endDate = new Date();
      if(beginSplit.length==1)
      {
        beginstr = endDate.getFullYear()+"-"+(endDate.getMonth()+1)+"-"+endDate.getDate()+" "+begin
      }
      else
      {
        beginstr = begin
      }

      let beginDate = new Date(beginstr);
      let diff = endDate.getTime() - beginDate.getTime();
      let sec = diff / 1000;
      return sec;
    },
    trimExpiredData() {
      const maxAgeSeconds = this.ChartTimelyRefresh * 60
      let i = 0
      while (i < this.option.xAxis.data.length) {
        if(this.getSecondByDateSub(this.option.xAxis.data[i]) > maxAgeSeconds)
        {
          this.option.xAxis.data.splice(i,1)
          for(let k=0;k<this.option.series.length;k++)
          {
            this.option.series[k].data.splice(i,1)
          }
          continue
        }
        i++
      }
    },
    captureCurrentDataZoom() {
      if (!this.echartsView || typeof this.echartsView.getOption !== 'function') {
        return null
      }
      const currentOption = this.echartsView.getOption()
      const zoomList = currentOption && currentOption.dataZoom
      if (!Array.isArray(zoomList) || !zoomList.length) {
        return null
      }
      return zoomList.map(item => ({
        start: item.start,
        end: item.end,
        startValue: item.startValue,
        endValue: item.endValue
      }))
    },
    applyCurrentDataZoom(currentZoom) {
      if (!Array.isArray(this.option.dataZoom)) {
        return this.option.dataZoom
      }
      if (!Array.isArray(currentZoom) || !currentZoom.length) {
        return this.option.dataZoom
      }
      return this.option.dataZoom.map((item, index) => {
        const current = currentZoom[index]
        if (!current) {
          return item
        }
        return {
          ...item,
          start: current.start,
          end: current.end,
          startValue: current.startValue,
          endValue: current.endValue
        }
      })
    },
    handleReadDataPush(realData) {
      if (!realData || !realData.Data || !Array.isArray(realData.Data) || !Array.isArray(this.detail.active)) {
        console.log("realData or realData.Data or this.detail.active is null")
        return
      }
      let matched = false
      for (let i = 0; i < this.detail.active.length; i++) {
        const activeItem = this.detail.active[i]
        const condition = activeItem && activeItem.condition ? activeItem.condition : null
        if (!condition || !condition.dataID) {
          console.log("condition or dataID is null")
          continue
        }
        for (let k = 0; k < realData.Data.length; k++) {
          const currentData = realData.Data[k]
          const deviceMatched = condition.isBandDevice ? realData.DeviceUuid === condition.deviceSN : true
          const dataMatched = condition.dataID === currentData.ModelDataUuid || condition.dataID === currentData.Uuid
          if (!deviceMatched || !dataMatched) {
            continue
          }
          const value = parseFloat(currentData.Value)
          if (isNaN(value)) {
            continue
          }
          console.log("value is "+value)  
          this.pendingRealDataMap[condition.deviceSN + condition.dataID] = value
          this.realDataComeMap[condition.deviceSN + condition.dataID] = true
          matched = true
        }
      }
      if (matched) {
        this.addData()
        this.realDataComeMap = {}
      }
    },
    // 添加实时数据
    addData() {
      const currentZoom = this.captureCurrentDataZoom()
      let c_data = this.getTime()
      c_data = moment(c_data).format(this.EchartsXFormat);

      for(let i=0;i<this.option.series.length;i++)
      {
        const series = this.option.series[i]
        const seriesData = this.seriesMap[series.dataID] || []
        if (Object.prototype.hasOwnProperty.call(this.pendingRealDataMap, series.dataID)) {
          seriesData.push(this.pendingRealDataMap[series.dataID])
        } else if (seriesData.length >= 1) {
          seriesData.push(seriesData[seriesData.length - 1])
        } else {
          seriesData.push(0)
        }
        series.data = seriesData
      }
      this.option.xAxis.data.push(c_data);
      this.trimExpiredData()
      this.pendingRealDataMap = {}
      if (this.echartsView) {
        this.echartsView.setOption({
          ...this.option,
          dataZoom: this.applyCurrentDataZoom(currentZoom)
        });
      }
    }
  },
  beforeDestroy () {
    clearInterval(this.ChartTimelyRefreshTimer)
    if (this.readDataPushHandler) {
      this.$EventBus.$off('readDataPush', this.readDataPushHandler)
    }
    if (this.activeEventName) {
      this.$EventBus.$off(this.activeEventName, this.activeEventHandler)
    }
    if (this.animateEventName) {
      this.$EventBus.$off(this.animateEventName, this.animateEventHandler)
    }
    if (this.dealWithRealDataFinishHandler) {
      this.$EventBus.$off("DealWithRealDataFinish", this.dealWithRealDataFinishHandler)
    }
    if (this.echartsView != null&&(typeof this.echartsView.dispose=="function")) {
      this.echartsView.clear();
      this.echartsView.dispose()
      this.echartsView = null
      this.currentEchartsTheme = ""
    }
  },
  created(){
    let _t = this
    const node = this.getNode()
    this.GetNodeObj = node
    node.on('change:data', ({ current }) => {
      if(current) {
        _t.detail = current.detail
      }
    })
    node.on('change:size', ({ current }) => {
      _t.detail.style.position.w = current.width
      _t.detail.style.position.h = current.height
      _t.$nextTick(() => {
        _t.onResize()
      })
    });
    this.detail = node.getData().detail
    this.syncEchartsThemeFromDetail(this.detail)
    this.editMode = node.getData().editMode
    this.showDeviceUuid = node.getData().showDeviceUuid
    this.IsToolBox = node.getData().IsToolBox
    this.syncSelectFromActive()
    this.restoreRuntimeSelection()
    this.getMonitorTree()
    _t.$EventBus.$on('cell-editMode', (data) => {
      _t.editMode = data.edit
      _t.IsToolBox = data.toolbox
      // _t.initComponents(_t.detail);
    })
  },
  mounted() {
      let _t = this
    this.$nextTick(function(){
      this.initComponents(this.detail);
      let activeEvent = this.detail.identifier+"activeEvent"//动作数据
      let animateEvent = this.detail.identifier+"animateEvent"//动作数据
      console.log('[ViewRealDataSmoothChartByDevice] mounted listeners', {
        identifier: this.detail && this.detail.identifier,
        activeEvent: activeEvent,
        active: this.detail && this.detail.active
      })
      this.readDataPushHandler = (data) => {
        _t.handleReadDataPush(data)
      }
      _t.$EventBus.$on('readDataPush', this.readDataPushHandler)
      this.activeEventName = activeEvent
      this.animateEventName = animateEvent
      this.dealWithRealDataFinishHandler = (data) => {
        if(_t.isFinish==0)
        {
          return
        }

        _t.addData()
        _t.isFinish=0
        _t.ShowChartVariable5IsCome = false
        _t.ShowChartVariable4IsCome = false
        _t.ShowChartVariable3IsCome = false
        _t.ShowChartVariable2IsCome = false
        _t.ShowChartVariable1IsCome = false
        _t.realDataComeMap = {}
        _t.pendingRealDataMap = {}
      }
      _t.$EventBus.$on("DealWithRealDataFinish", this.dealWithRealDataFinishHandler)
      this.activeEventHandler = (data) => {
        console.log('[ViewRealDataSmoothChartByDevice] activeEvent received', data)
        let valueObj = parseFloat(data.result)
        if(!isNaN(valueObj)) {
          const seriesKey = data.DeviceSN+data.dataID
          if (_t.seriesMap[seriesKey]) {
            _t.realDataComeMap[seriesKey] = true
            _t.pendingRealDataMap[seriesKey] = parseFloat(data.result)
          }
          if (data.ID == "ShowChartVariable1") {
            _t.ShowChartVariable1IsCome = true
          } else if (data.ID == "ShowChartVariable2") {
            _t.ShowChartVariable2IsCome = true
          } else if (data.ID == "ShowChartVariable3") {
            _t.ShowChartVariable3IsCome = true
          } else if (data.ID == "ShowChartVariable4") {
            _t.ShowChartVariable4IsCome = true
          } else if (data.ID == "ShowChartVariable5") {
            _t.ShowChartVariable5IsCome = true
          }
          _t.isFinish=1
        }
        else{
          console.log("isanna",data.result)
        }
      }
      _t.$EventBus.$on(activeEvent, this.activeEventHandler)
      this.animateEventHandler = (data) => {
        _t.isStart = data
      }
      _t.$EventBus.$on(animateEvent, this.animateEventHandler)
    });
  }
}
</script>

<style lang="less">
.view-chart-real-data-by-device {
  display: flex;
  flex-direction: column;
